def generate_snippet(doc, query, window=5):
    words = doc.split()
    q = query.lower()
    try:
        idx = [i for i, w in enumerate(words) if q in w.lower()][0]
        start = max(0, idx - window)
        end = min(len(words), idx + window + 1)
        snippet = " ".join(words[start:end])
        # Highlight
        return snippet.replace(query, f"**{query}**")
    except:
        return doc[:50] + "..."

text = "Information retrieval is the science of searching for information in documents."
print(f"Snippet: {generate_snippet(text, 'science')}")
